// Initialize the data with a default set of values for the necessary channels to have jibo animating his top, middle, and bottom body rotations.
// This includes some eye and overlay texture related default values in order to make sure Jibo's eye is showing centered on his screen

import * as fs from "fs";
import * as path from 'path';
import JiboKeyframeInfo from "../JiboKeyframeInfo";
import Channels from "./Channels";
import Runtime from "../Runtime";

var animData = {
    "header": {
        "fileType":"Animation",
        "version":"0.001",
        "creationTime":1418336756906
    },
    "content":{
        "name":"AnythingElse_01.dae",
        "channels":[],
        "events":[]
    }
};

export default class KeysUtils {
    static keysToAnimObjectAsync(keysPath, cb) {
        // Load .keys file asynchronously
        fs.readFile(keysPath, 'utf8', (err, data) => {
            if (err) {
                console.log("\nError parsing \"" + keysPath + "\". " + err + "\n");
                process.exit(1);
            }
            else {
                let keysData = JSON.parse(data);
                JiboKeyframeInfo.onLoad(keysData);
                // use the base name of the uri for the anim data "name"
                let baseName = path.basename(keysPath);

                let animObj = KeysUtils.keysObjToAnimObject(keysData, baseName);
                cb(animObj);
            }
        });
    }

    static keysToAnim(keysPath, animPath) {

        console.log(keysPath);
        let animData = KeysUtils.keysToAnimObject(keysPath);

        try{
            fs.writeFileSync(animPath, JSON.stringify(animData, null, '    '), 'utf8');
        } catch(error) {
            console.log("\nERROROROROROR\n");
            process.exit(1);
        }

}

    static keysToAnimObject(keysPath) {
        let keysData;
        try{
            // Load .keys file
            keysData = JSON.parse(fs.readFileSync(keysPath, 'utf8'));
            JiboKeyframeInfo.onLoad(keysData);
        } catch(error) {
            console.log("\nError parsing \"" + keysPath + "\". " + error + "\n");
            process.exit(1);
        }

        // use the base name of the uri for the anim data "name"
        let baseName = path.basename(keysPath);
        return KeysUtils.keysObjToAnimObject(keysData, baseName);
    }


    static keysObjToAnimObject(keysData, name) {
        /*
         * Fill out "header" fields that need to be changed. Should look like so
         *
         *	"header": {
         *     "fileType": "DOFAnimation",
         *      "version": "0.001",
         *      "creationTime": 1418336756906
         *  },
         */
        animData.header.creationTime = (new Date()).getTime();
        animData.header.version = keysData.version;
        /*
         * Fill out "content" fields that need to be changed. Should look like so
         *
         *	"content": {
         *      "name": "example.keys",
     *          "channels": [
                    {
                        "name": "Top",
                        "type": "number",
                        "keyframes": [
                            {
                                "time": 0,
                                "rotation": 0
                            },
                            ...
                        ]
                    },
                    ...
                ],
                "events": [
                    {
                        "time": 0,
                        "payload": {object}
                    },
                    ...
                ]
         *  },
         */

        // reset data!
        animData.content.name = name;
        animData.content.channels = [];
        animData.content.events = [];

        let animChannels = {};

        // For each frame calculate all dof and event values and save them to file
        for(let frame = 0; frame<keysData.duration; frame++){
            let timeInSeconds = Channels.framesToSeconds(frame, keysData.framerate);
            let dofs = Runtime.evaluateAllDOFLayers(keysData, JiboKeyframeInfo, timeInSeconds);
            let events = Runtime.evaluateAllEventLayers(keysData, JiboKeyframeInfo, timeInSeconds);

            for(let dofName in dofs){
                if( typeof animChannels[dofName] === "undefined") {
                    animChannels[dofName] = {
                        dofName: dofName,
                        length: keysData.duration/keysData.framerate,
                        times: [timeInSeconds],
                        values: [ dofs[dofName] ]
                    };

                    animData.content.channels.push(animChannels[dofName]);
                } else {
                    animChannels[dofName].times.push(timeInSeconds);
                    animChannels[dofName].values.push(dofs[dofName]);
                }
            }

            for(let i = 0; i < events.length; i++) {

                let animEvent = {
                    time: timeInSeconds,
                    eventName: events[i].name,
                    payload: events[i].payload
                };

                animData.content.events.push(animEvent);
            }
        }
        return animData;
    }
}
