import DOFBaseLayer from '../bases/DOFBaseLayer';

const LightingInfo = {
    layerType: "Lighting",
    properties: {
        Enabled: {
            type: "bool",
            defaultValue: true,
            blendOperation: "lastOneWins"
        },
        Amount: {
            type: "float",
            defaultValue: 1,
            blendOperation: "add"        
        },    
        Brightness: {
            type: "float",
            defaultValue: 0.0,
            blendOperation: "add"        
        },
        Gradient: {
            type: "float",
            defaultValue: 0.5,
            blendOperation: "add"
        },
        Radius: {
            type: "float",
            defaultValue: 300,
            blendOperation: "add"        
        },                        
        Light: {
            type: "rgb",
            defaultValue: {
                r: 255,
                g: 255,
                b: 255
            },
            blendOperation: "add"
        },
        Mid: {
            type: "rgb",
            defaultValue: {
                r: 192,
                g: 186,
                b: 182
            },
            blendOperation: "add"
        },
        Dark: {
            type: "rgb",
            defaultValue: {
                r: 90,
                g: 85,
                b: 82
            },
            blendOperation: "add"
        }        
    }
};


export default class LightingLayer extends DOFBaseLayer {

    static generateDofs(props){
        return {
            lighting_amount: !props.Enabled ? 0 : props.Amount,
            lighting_brightness: props.Brightness,
            lighting_gradient: props.Gradient,
            lighting_radius: props.Radius,
            lighting_light_redChannel: props.Light.r,
            lighting_light_greenChannel: props.Light.g,
            lighting_light_blueChannel: props.Light.b,
            lighting_mid_redChannel: props.Mid.r,
            lighting_mid_greenChannel: props.Mid.g,
            lighting_mid_blueChannel: props.Mid.b,
            lighting_dark_redChannel: props.Dark.r,
            lighting_dark_greenChannel: props.Dark.g,
            lighting_dark_blueChannel: props.Dark.b
        };
    }

    static getInfo() {
        return LightingInfo;
    }
} 